int LoadStringFallback(HINSTANCE hInstance, UINT uID, LPSTR lpBuffer, int nBufferMax) {
  auto it = g_fallback_strings.find(uID);
  if (it != g_fallback_strings.end()) {
    strncpy(lpBuffer, it->second, nBufferMax);
    lpBuffer[nBufferMax - 1] = '\0';
    return strlen(lpBuffer);
  }
  if (nBufferMax > 0) lpBuffer[0] = '\0';
  return 0;
}
